SELECT
    COUNT(CASE WHEN risk_score >= 70 THEN 1 END) as high_risk,
    COUNT(CASE WHEN risk_score >= 50 AND risk_score < 70 THEN 1 END) as medium_risk,
    COUNT(CASE WHEN risk_score < 50 THEN 1 END) as low_risk
FROM shipments;

-- Show sample records
